const ALL_WEIGHTS = [100, 200, 300, 400, 500, 600, 700, 800, 900] as const;

export function getWeightsForFont(family: string | undefined): number[] {
  if (!family) return [...ALL_WEIGHTS];
  const bits = FONT_WEIGHTS[family];
  if (bits === undefined) return [...ALL_WEIGHTS];
  return ALL_WEIGHTS.filter((_, i) => bits & (1 << i));
}

export function hasItalicForFont(family: string | undefined): boolean {
  if (!family) return true;
  const bits = FONT_WEIGHTS[family];
  if (bits === undefined) return true;
  return (bits & 512) !== 0;
}
